mapper.select:
SELECT DIET_SEQ, DIET_NAME, DIET_CALORIES
FROM DIET
    AND E.DIET_SEQ = #{diet_seq}

mapper.update:
UPDATE DIET SET
                DIET_NAME = #{diet_name},
                FOOD_NAME  = #{food_name},
                FOOD_NUMBER = #{food_number},
                DIET_CALORIES = #{diet_calories}
WHERE DIET_SEQ = #{diet_seq}
